def load_checkpoint_weights(model: nn.Module, checkpoint_obj: Any, strict: bool = False) -> None:
    if isinstance(checkpoint_obj, dict):
        if "state_dict" in checkpoint_obj and isinstance(checkpoint_obj["state_dict"], dict):
            state_dict = checkpoint_obj["state_dict"]
        elif "model_state_dict" in checkpoint_obj and isinstance(checkpoint_obj["model_state_dict"], dict):
            state_dict = checkpoint_obj["model_state_dict"]
        else:
            state_dict = checkpoint_obj
    else:
        raise ValueError("Checkpoint format is not a supported state_dict container.")
    cleaned = {}
    for k, v in state_dict.items():
        if k.startswith("module."):
            cleaned[k[len("module."):]] = v
        else:
            cleaned[k] = v
    model.load_state_dict(cleaned, strict=strict)


def create_dataloaders(
    train_dir: str,
    val_dir: Optional[str],
    image_size: int,
    batch_size: int,
    num_workers: int
):
    train_tf = transforms.Compose([
        transforms.Resize((image_size, image_size)),
        transforms.RandomHorizontalFlip(),
        transforms.ToTensor(),
    ])
    val_tf = transforms.Compose([
        transforms.Resize((image_size, image_size)),
        transforms.ToTensor(),
    ])

    train_ds = datasets.ImageFolder(train_dir, transform=train_tf)
    val_ds = datasets.ImageFolder(val_dir, transform=val_tf) if val_dir else None

    train_loader = DataLoader(
        train_ds,
        batch_size=batch_size,
        shuffle=True,
        num_workers=num_workers,
        pin_memory=True,
    )
    val_loader = None
    if val_ds is not None:
        val_loader = DataLoader(
            val_ds,
            batch_size=batch_size,
            shuffle=False,
            num_workers=num_workers,
            pin_memory=True,
        )
    return train_ds, val_ds, train_loader, val_loader


def freeze_backbone(model: nn.Module, model_name: str) -> None:
    for p in model.parameters():
        p.requires_grad = False

    mn = model_name.lower()
    if mn.startswith("resnet"):
        for p in model.fc.parameters():
            p.requires_grad = True
    elif mn.startswith("mobilenet_v3"):
        for p in model.classifier.parameters():
            p.requires_grad = True
    elif mn.startswith("efficientnet"):
        for p in model.classifier.parameters():
            p.requires_grad = True
    else:
        for p in model.parameters():
            p.requires_grad = True


def evaluate(model: nn.Module, loader: DataLoader, device: torch.device, criterion: nn.Module):
    model.eval()
    total_loss = 0.0
    total = 0
    correct = 0
    with torch.no_grad():
        for x, y in loader:
            x = x.to(device, non_blocking=True)
            y = y.to(device, non_blocking=True)
            logits = model(x)
            loss = criterion(logits, y)
            total_loss += loss.item() * x.size(0)
            preds = logits.argmax(dim=1)
            total += y.size(0)
            correct += (preds == y).sum().item()
    avg_loss = total_loss / max(total, 1)
    acc = correct / max(total, 1)
    return avg_loss, acc


def train(
    model: nn.Module,
    train_loader: DataLoader,
    val_loader: Optional[DataLoader],
    device: torch.device,
    epochs: int,
    lr: float,
    output_dir: str
):
    os.makedirs(output_dir, exist_ok=True)
    criterion = nn.CrossEntropyLoss()
    optimizer = optim.Adam((p for p in model.parameters() if p.requires_grad), lr=lr)
    best_val_acc = -1.0

    model.to(device)

    for epoch in range(1, epochs + 1):
        model.train()
        running_loss = 0.0
        total = 0
        correct = 0

        for x, y in train_loader:
            x = x.to(device, non_blocking=True)
            y = y.to(device, non_blocking=True)

            optimizer.zero_grad(set_to_none=True)
            logits = model(x)
            loss = criterion(logits, y)
            loss.backward()
            optimizer.step()

            running_loss += loss.item() * x.size(0)
            preds = logits.argmax(dim=1)
            total += y.size(0)
            correct += (preds == y).sum().item()

        train_loss = running_loss / max(total, 1)
        train_acc = correct / max(total, 1)

        metrics = {
            "epoch": epoch,
            "train_loss": train_loss,
            "train_acc": train_acc,
        }

        if val_loader is not None:
            val_loss, val_acc = evaluate(model, val_loader, device, criterion)
            metrics["val_loss"] = val_loss
            metrics["val_acc"] = val_acc

            if val_acc > best_val_acc:
                best_val_acc = val_acc
